class MusicPlayer:
    def __init__(self):
        self.songs = [
            "Un collier de tes bras", "Un coup au cœur",
            "C'est encore une souris", "Je ne veux plus être un dragueur",
            "C'est tout comme", "Danny Boy", "Croque la pomme"
        ]
        self.current_song = None

    def play_song(self, song_name):
        if song_name in self.songs:
            self.current_song = song_name
            print(f"Now playing: {song_name}")
        else:
            print("Song not found.")

    def list_songs(self):
        print("Danny Boy et ses Pénitents' songs:")
        for i, song in enumerate(self.songs, 1):
            print(f"{i}. {song}")

# Example usage
player = MusicPlayer()
player.list_songs()
player.play_song("Danny Boy")
